import java.util.*;class A{static int W,H;static int[][]T,LK;static int[][][]RM={{{},{0,2},{1,2},{3,2}},{{},{1,3},{3,1}},{{},{0,2}},{{},{0,3},{1,2}},{{},{0,1},{1,2}},{{},{1,3},{3,1}},{{},{0,2},{1,2}},{{},{3,2},{1,2}},{{},{0,2},{3,2}},{{},{0,3}},{{},{0,1}},{{},{1,2}},{{},{3,2}}};static int[][]RG={{0},{1},{2,3},{3,2},{4,5},{5,4},{6,7,8,9},{7,8,9,6},{8,9,6,7},{9,6,7,8},{10,11,12,13},{11,12,13,10},{12,13,10,11},{13,10,11,12}};static int[]DX={0,1,0,-1},DY={-1,0,1,0},OPP={2,3,0,1};static Map<Integer,Integer>rot=new HashMap<>();static int gt(int x,int y){return rot.getOrDefault(y*99+x,T[y][x]);}static Map<Integer,Map<Integer,Integer>>RMM=new HashMap<>();static int gx(int t,int e){return RMM.getOrDefault(t,Map.of()).getOrDefault(e,-1);}static List<int[]>plan=new ArrayList<>();static boolean dfs(int x,int y,int e){if(y>=H)return true;if(x<0||x>=W||y<0)return false;int o=T[y][x],k=y*99+x;for(int c:RG[o]){if(LK[y][x]==1&&c!=gt(x,y))continue;int ex=gx(c,e);if(ex<0)continue;int nx=x+DX[ex],ny=y+DY[ex],ne=OPP[ex];Integer prev=rot.get(k);rot.put(k,c);if(dfs(nx,ny,ne)){if(c!=T[y][x])plan.add(new int[]{x,y,c});return true;}if(prev!=null)rot.put(k,prev);else rot.remove(k);}return false;}public static void main(String[]args){var s=new Scanner(System.in);W=s.nextInt();H=s.nextInt();T=new int[H][W];LK=new int[H][W];int[][]rm={{},{0,2,1,2,3,2},{1,3,3,1},{0,2},{0,3,1,2},{0,1,1,2},{1,3,3,1},{0,2,1,2},{3,2,1,2},{0,2,3,2},{0,3},{0,1},{1,2},{3,2}};for(int i=0;i<14;i++){var m=new HashMap<Integer,Integer>();for(int j=0;j<rm[i].length;j+=2)m.put(rm[i][j],rm[i][j+1]);RMM.put(i,m);}for(int y=0;y<H;y++)for(int x=0;x<W;x++){T[y][x]=s.nextInt();LK[y][x]=T[y][x]<0?1:0;T[y][x]=Math.abs(T[y][x]);}int EX=s.nextInt();var Q=new ArrayList<String>();for(;;){int yi=s.nextInt(),xi=s.nextInt();String en=s.next();int e=en.charAt(0)=='T'?0:en.charAt(0)=='R'?1:3;int R=s.nextInt();for(int i=0;i<R;i++){s.nextInt();s.nextInt();s.next();}if(Q.isEmpty()){rot.clear();plan.clear();if(dfs(xi,yi,e))for(var st:plan){int o=T[st[1]][st[0]],r=-1;for(int i=0;i<RG[o].length;i++)if(RG[o][i]==st[2])r=i;if(r<=0)continue;String d=r<=2?"RIGHT":"LEFT";int cnt=r<=2?r:4-r;for(int i=0;i<cnt;i++)Q.add(st[0]+" "+st[1]+" "+d);T[st[1]][st[0]]=st[2];}}System.out.println(Q.isEmpty()?"WAIT":Q.remove(0));}}}